const b = $input.first().json.body || $input.first().json;
const v = (k) => (b[k] == null ? '' : String(b[k])).trim();
const spam = Object.keys(b).some((k) => k.charAt(0) === '_' && String(b[k]).length > 0);
const step = v('preferred_next_step').toLowerCase();
const need = v('need').toLowerCase();
// Hot = ready to talk/build; cold = needs education first.
const hot = /book|strategy|session|assessment|review|map|voice|intake/.test(step) || /crm|automation|brandpresence|localpresence|agent/.test(need);
return [{ json: {
  spam,
  lead_temp: hot ? 'hot' : 'cold',
  name: v('name'),
  email: v('email'),
  phone: v('phone'),
  company: v('company'),
  industry: v('industry'),
  market_lane: v('market_lane'),
  need: v('need'),
  preferred_next_step: v('preferred_next_step'),
  message: v('bottleneck'),
  desired_result: v('desired_result'),
  page_url: v('page_url'),
  utm: b.utm || {},
  raw: b
}}];

